const { PromptTemplate } = require('@langchain/core/prompts');

// ============================================================
// CHUNKER INTELIGENTE POR TEMAS — GPT-4o
// Analiza el documento completo y divide por temas semánticos
// Optimizado para carga en PGVector
// ============================================================

// Buscar contenido en múltiples campos posibles
let documentContent = $input.item.json?.data || $input.item.json?.text || $input.item.json?.content || $input.item.json?.body;

// Si hay datos binarios, convertir a string
if (!documentContent && $input.item.binary) {
    const binaryKey = Object.keys($input.item.binary)[0];
    if (binaryKey) {
        documentContent = Buffer.from($input.item.binary[binaryKey].data, 'base64').toString('utf-8');
    }
}

if (!documentContent) {
    throw new Error('No document found in input. Available fields: ' + JSON.stringify(Object.keys($input.item.json || {})));
}

const llm = await this.getInputConnectionData('ai_languageModel', 0);

function cleanText(text) {
    return text.replace(/\s+/g, ' ').trim();
}

function escapeForTemplate(text) {
    return text.replace(/\{/g, '{{').replace(/\}/g, '}}');
}

const fullText = cleanText(documentContent);

// ============================================================
// CONFIGURACIÓN
// ============================================================
const MAX_CHUNK_SIZE = 1500;    // Máximo caracteres por chunk
const MIN_CHUNK_SIZE = 200;     // Mínimo caracteres por chunk
const MAX_INPUT_LENGTH = 30000; // Máximo para enviar al LLM de una vez

// ============================================================
// PASO 1: El LLM analiza el documento y lo divide por temas
// ============================================================

async function splitByTopics(text) {
    // Si el texto es muy corto, devolver como un solo chunk
    if (text.length <= MAX_CHUNK_SIZE) {
        return [text];
    }

    // Si el documento es muy largo, dividirlo en secciones primero
    // y procesar cada sección por separado
    const textToProcess = text.length > MAX_INPUT_LENGTH
        ? text.substring(0, MAX_INPUT_LENGTH)
        : text;

    const escapedText = escapeForTemplate(textToProcess);

    const promptText = `Eres un experto en organización de información jurídica para bases de datos vectoriales (PGVector).

Tu tarea es dividir esta sentencia judicial en bloques temáticos independientes. Cada bloque debe:
1. Cubrir UN solo tema o concepto jurídico específico
2. Ser AUTOCONTENIDO: debe entenderse sin necesidad de leer otros bloques
3. Incluir contexto completo (carátula, tribunal, normativa citada si es relevante)
4. Tener entre ${MIN_CHUNK_SIZE} y ${MAX_CHUNK_SIZE} caracteres aproximadamente
5. Si hay secciones legales (VISTOS, CONSIDERANDO, RESUELVE), respetarlas

REGLAS IMPORTANTES:
- Si varias consideraciones son del MISMO tema (ej: normativa de jubilaciones), UNIFICARLAS en un solo bloque
- Si una consideración es de un tema DISTINTO, ponerla en un bloque separado
- Cada bloque debe empezar mencionando el contexto legal
- NO incluir metadatos como "Chunk 1" o "Sección:" en el contenido
- NO repetir información entre bloques
- NO parafrasear, mantené el texto jurídico original

SENTENCIA JUDICIAL:
${escapedText}

FORMATO DE RESPUESTA:
Devolvé ÚNICAMENTE los bloques separados por la línea exacta:
===CHUNK===
No agregues explicaciones, títulos ni numeración. Solo el contenido de cada bloque separado por ===CHUNK===

Ejemplo de formato correcto:
En autos "García, María c/ ANSES s/ reajustes varios" (Expte 12345/2023), la Cámara Federal de la Seguridad Social, Sala II, analiza la procedencia del reajuste por movilidad jubilatoria conforme a la Ley 24.241...
===CHUNK===
Respecto de la aplicación del artículo 14 bis de la Constitución Nacional y su vinculación con la movilidad de las prestaciones, el tribunal consideró que...
===CHUNK===
Por lo expuesto, SE RESUELVE: 1) Hacer lugar a la demanda incoada...


IMPORTANTE: NUNCA parafrasees, reescribas ni agregues información que no esté en el texto original. Mantené el contenido jurídico exacto, solo reorganizalo en bloques temáticos.`;

    const prompt = PromptTemplate.fromTemplate(promptText);
    const chain = prompt.pipe(llm);

    try {
        const response = await chain.invoke();
        const responseText = response.content || response.text || response.toString();

        // Parsear la respuesta del LLM
        let rawChunks = responseText
            .split('===CHUNK===')
            .map(c => c.trim())
            .filter(c => c.length > 0);

        // Si el LLM no respetó el formato, intentar con doble salto de línea
        if (rawChunks.length <= 1) {
            rawChunks = responseText
                .split(/\n\n\n+/)
                .map(c => c.trim())
                .filter(c => c.length > 0);
        }

        // Si aún así hay un solo chunk, devolver el texto dividido por tamaño
        if (rawChunks.length <= 1) {
            console.log('LLM returned single chunk, falling back to size-based split');
            return fallbackSplit(text);
        }

        return rawChunks;

    } catch (error) {
        console.log('LLM topic analysis failed, using fallback:', error.message);
        return fallbackSplit(text);
    }
}

// ============================================================
// PASO 2: Fallback — División por tamaño si el LLM falla
// ============================================================

function fallbackSplit(text) {
    const chunks = [];
    let remaining = text;

    while (remaining.length > 0) {
        if (remaining.length <= MAX_CHUNK_SIZE) {
            chunks.push(remaining);
            break;
        }

        // Buscar el mejor punto de corte antes del máximo
        let breakPoint = MAX_CHUNK_SIZE;
        const searchArea = remaining.substring(Math.floor(MAX_CHUNK_SIZE * 0.7), MAX_CHUNK_SIZE);

        // Buscar fin de oración
        const sentenceEnd = searchArea.lastIndexOf('. ');
        if (sentenceEnd !== -1) {
            breakPoint = Math.floor(MAX_CHUNK_SIZE * 0.7) + sentenceEnd + 2;
        }

        chunks.push(remaining.substring(0, breakPoint).trim());
        remaining = remaining.substring(breakPoint).trim();
    }

    return chunks;
}

// ============================================================
// PASO 3: Post-procesamiento — Validar y limpiar chunks
// ============================================================

async function processDocument(text) {
    let rawChunks;

    // Si el documento es muy largo, procesarlo en partes
    if (text.length > MAX_INPUT_LENGTH) {
        rawChunks = [];
        let offset = 0;

        while (offset < text.length) {
            // Buscar un buen punto de corte para la sección
            let sectionEnd = offset + MAX_INPUT_LENGTH;

            if (sectionEnd < text.length) {
                // Intentar cortar en un punto limpio
                const searchArea = text.substring(
                    Math.max(offset + MAX_INPUT_LENGTH - 2000, offset),
                    sectionEnd
                );
                const lastPeriod = searchArea.lastIndexOf('. ');
                if (lastPeriod !== -1) {
                    sectionEnd = Math.max(offset + MAX_INPUT_LENGTH - 2000, offset) + lastPeriod + 2;
                }
            } else {
                sectionEnd = text.length;
            }

            const section = text.substring(offset, sectionEnd);
            const sectionChunks = await splitByTopics(section);
            rawChunks.push(...sectionChunks);

            offset = sectionEnd;
        }
    } else {
        rawChunks = await splitByTopics(text);
    }

    // Post-procesamiento: fusionar chunks muy pequeños
    const finalChunks = [];
    let buffer = '';

    for (const chunk of rawChunks) {
        if (buffer.length > 0) {
            // Si el buffer + chunk caben, fusionar
            if (buffer.length + chunk.length + 1 <= MAX_CHUNK_SIZE) {
                buffer += ' ' + chunk;
                continue;
            } else {
                // Guardar el buffer y empezar de nuevo
                finalChunks.push(buffer);
                buffer = '';
            }
        }

        if (chunk.length < MIN_CHUNK_SIZE) {
            buffer = chunk;
        } else if (chunk.length > MAX_CHUNK_SIZE) {
            // Si un chunk es muy grande, subdividirlo
            const subChunks = fallbackSplit(chunk);
            finalChunks.push(...subChunks);
        } else {
            finalChunks.push(chunk);
        }
    }

    // No olvidar el buffer final
    if (buffer.length > 0) {
        if (finalChunks.length > 0 &&
            finalChunks[finalChunks.length - 1].length + buffer.length + 1 <= MAX_CHUNK_SIZE) {
            finalChunks[finalChunks.length - 1] += ' ' + buffer;
        } else {
            finalChunks.push(buffer);
        }
    }

    return finalChunks;
}

// ============================================================
// EJECUTAR
// ============================================================

const processedChunks = await processDocument(fullText);

const returnData = processedChunks.map((content, index) => ({
    json: {
        content: content,
        chunk: index + 1,
        chunk_size: content.length,
        total_chunks: processedChunks.length
    }
}));

return returnData;
